var fontPopup     = document.getElementById('font-popup');
var fontSearch    = document.getElementById('font-search');
var fontList      = document.getElementById('font-list');
var fontSelectBtn = document.getElementById('font-select-btn');
var fontSelectLabel = document.getElementById('font-select-label');

function buildFontList(query) {
  var q = (query || '').toLowerCase();
  var filtered = PRESET_FONTS.filter(function(f) {
    return !q || f.name.toLowerCase().includes(q) || f.value.toLowerCase().includes(q);
  });

  var groups = {};
  filtered.forEach(function(f) {
    if (!groups[f.group]) groups[f.group] = [];
    groups[f.group].push(f);
  });

  fontList.innerHTML = '';

  var browserFonts = [];
  try {
    document.fonts.forEach(function(ff) {
      var n = ff.family.replace(/['"]/g, '');
      if (!q || n.toLowerCase().includes(q)) browserFonts.push(n);
    });
    browserFonts = [...new Set(browserFonts)].sort();
  } catch(e) {}

  Object.keys(groups).forEach(function(group) {
    var label = document.createElement('div');
    label.className = 'font-section-label';
    label.textContent = group;
    fontList.appendChild(label);
    groups[group].forEach(function(f) { appendFontItem(f.name, f.value); });
  });

  if (browserFonts.length) {
    var label = document.createElement('div');
    label.className = 'font-section-label';
    label.textContent = 'Loaded in browser';
    fontList.appendChild(label);
    browserFonts.forEach(function(name) {
      appendFontItem(name, name);
    });
  }
}

function appendFontItem(name, value) {
  var item = document.createElement('button');
  item.type = 'button';
  item.setAttribute('role', 'option');
  item.setAttribute('aria-selected', cfgFont === value ? 'true' : 'false');
  item.className = 'font-item' + (cfgFont === value ? ' active' : '');
  var previewSpan = document.createElement('span');
  previewSpan.className = 'font-item-preview';
  previewSpan.style.fontFamily = value + ', sans-serif';
  previewSpan.textContent = 'Aa';
  var nameSpan = document.createElement('span');
  nameSpan.className = 'font-item-name';
  nameSpan.textContent = name;
  item.appendChild(previewSpan);
  item.appendChild(nameSpan);
  item.addEventListener('click', function() {
    cfgFont = value;
    fontSelectLabel.textContent = name;
    closeFontPopup();
    readConfig();
    scheduleRender(0);
    fontSelectBtn.focus();
  });
  fontList.appendChild(item);
}

var fontPopupController = createPopupController({
  popup: fontPopup,
  trigger: fontSelectBtn,
  visibility: { focusSelector: '#font-search' },
  beforeOpen: function() {
    buildFontList('');
    fontSearch.value = '';
    positionAnchoredPopup(fontPopup, fontSelectBtn, { width: 220, height: 320 });
  },
  contains: function(target) {
    return !!(target.closest('#font-popup') || target.closest('#font-select-btn'));
  },
  repositionOnResize: true,
  position: function() { positionAnchoredPopup(fontPopup, fontSelectBtn, { width: 220, height: 320 }); },
});

function openFontPopup() {
  fontPopupController.open({ focusFirst: true });
}

function closeFontPopup(restoreFocus) {
  fontPopupController.close({ restoreFocus: !!restoreFocus });
}

fontSearch.addEventListener('input', function() {
  buildFontList(fontSearch.value);
});

var paddingNum    = document.getElementById('cfg-padding');
var paddingSlider = document.getElementById('cfg-padding-slider');

function setPadding(val) {
  val = Math.max(0, Math.min(120, parseInt(val, 10) || 0));
  cfgPadding = val;
  paddingNum.value    = val;
  paddingSlider.value = val;
  readConfig();
  scheduleRender(200);
}

paddingNum.addEventListener('input', function() { setPadding(paddingNum.value); });
paddingSlider.addEventListener('input', function() { setPadding(paddingSlider.value); });


var currentLeftPanel = 'code';
var currentMobilePanel = 'code';

function setMobilePanel(panel) {
  currentMobilePanel = panel;
  document.body.dataset.mobilePanel = panel;
  syncModeButtons();
}

function setLeftPanelMode(panel) {
  currentLeftPanel = panel === 'config' ? 'config' : 'code';
  if (currentLeftPanel === 'code') {
    editorView.hidden = false;
    editorView.style.display = 'flex';
    configView.hidden = true;
    configView.classList.remove('visible');
    configView.setAttribute('aria-hidden', 'true');
    editorView.setAttribute('aria-hidden', 'false');
  } else {
    editorView.hidden = true;
    editorView.style.display = 'none';
    configView.hidden = false;
    configView.classList.add('visible');
    configView.setAttribute('aria-hidden', 'false');
    editorView.setAttribute('aria-hidden', 'true');
    refreshAllColorUIs();
  }
  syncModeButtons();
}

function syncModeButtons() {
  document.querySelectorAll('[data-left-panel]').forEach(function(btn) {
    var active = btn.dataset.leftPanel === currentLeftPanel;
    btn.classList.toggle('is-active', active);
    btn.setAttribute('aria-pressed', active ? 'true' : 'false');
  });
  document.querySelectorAll('[data-mobile-panel]').forEach(function(btn) {
    var active = btn.dataset.mobilePanel === currentMobilePanel;
    btn.classList.toggle('is-active', active);
    btn.setAttribute('aria-pressed', active ? 'true' : 'false');
  });
}

function selectLeftPanel(panel, focusButton) {
  setLeftPanelMode(panel);
  setMobilePanel(panel);
  if (focusButton) {
    var btn = document.querySelector('[data-left-panel="' + panel + '"]');
    if (btn) btn.focus();
  }
}

function selectMobilePanel(panel, focusButton) {
  if (panel === 'code' || panel === 'config') setLeftPanelMode(panel);
  setMobilePanel(panel);
  if (focusButton) {
    var btn = document.querySelector('[data-mobile-panel="' + panel + '"]');
    if (btn) btn.focus();
  }
}

function moveWithinSegmentedControl(button, direction) {
  var group = button.closest('[data-segmented-control]');
  if (!group) return;
  var buttons = Array.prototype.slice.call(group.querySelectorAll('button'));
  var index = buttons.indexOf(button);
  var nextIndex = index;
  if (direction === 'Home') nextIndex = 0;
  else if (direction === 'End') nextIndex = buttons.length - 1;
  else nextIndex = (index + (direction === 'ArrowRight' ? 1 : -1) + buttons.length) % buttons.length;
  var next = buttons[nextIndex];
  if (!next) return;
  if (next.dataset.leftPanel) selectLeftPanel(next.dataset.leftPanel, true);
  else if (next.dataset.mobilePanel) selectMobilePanel(next.dataset.mobilePanel, true);
}

function attachSegmentedControl(selector, selectFn) {
  document.querySelectorAll(selector).forEach(function(button) {
    button.addEventListener('click', function() { selectFn(button.dataset.leftPanel || button.dataset.mobilePanel, false); });
    button.addEventListener('keydown', function(e) {
      if (!["ArrowLeft", "ArrowRight", "Home", "End"].includes(e.key)) return;
      e.preventDefault();
      moveWithinSegmentedControl(button, e.key);
    });
  });
}

attachSegmentedControl('[data-left-panel]', selectLeftPanel);
attachSegmentedControl('[data-mobile-panel]', selectMobilePanel);
setLeftPanelMode('code');
setMobilePanel('code');


function writeClipboardText(value, success, failure, sourceBtn) {
  if (!navigator.clipboard || !navigator.clipboard.writeText) {
    setCopyFeedback(sourceBtn, 'err');
    showToast(failure || 'Copy is not supported in this browser.');
    return;
  }
  navigator.clipboard.writeText(value).then(function() {
    setCopyFeedback(sourceBtn, 'ok');
    showToast(success || 'Copied!');
    if (typeof setExportDropdownOpen === 'function') setExportDropdownOpen(false, false);
  }).catch(function() {
    setCopyFeedback(sourceBtn, 'err');
    showToast(failure || 'Copy failed.');
  });
}

function copySource() {
  writeClipboardText(editor.value, 'Source copied!', 'Copy source failed.', copySourceBtn);
}

function mermaidBodyStart(source) {
  var text = String(source || '').replace(/^---[\s\S]*?---\s*/, '');
  var lines = text.split(/\r?\n/);
  for (var i = 0; i < lines.length; i++) {
    var line = lines[i].trim();
    if (!line || line.indexOf('%%') === 0) continue;
    return line;
  }
  return '';
}

function detectAgentFamily(source) {
  var first = mermaidBodyStart(source).toLowerCase();
  if (/^(graph|flowchart)\b/.test(first)) return { family: 'flowchart', narrower: 'asFlowchart' };
  if (/^statediagram(?:-v2)?\b/.test(first)) return { family: 'state', narrower: 'asState' };
  if (/^sequencediagram\b/.test(first)) return { family: 'sequence', narrower: 'asSequence' };
  if (/^timeline\b/.test(first)) return { family: 'timeline', narrower: 'asTimeline' };
  if (/^classdiagram\b/.test(first)) return { family: 'class', narrower: 'asClass' };
  if (/^erdiagram\b/.test(first)) return { family: 'er', narrower: 'asEr' };
  if (/^journey\b/.test(first)) return { family: 'journey', narrower: 'asJourney' };
  if (/^architecture\b/.test(first)) return { family: 'architecture', narrower: 'asArchitecture' };
  if (/^xychart(?:-beta)?\b/.test(first)) return { family: 'xychart', narrower: 'asXyChart' };
  if (/^pie\b/.test(first)) return { family: 'pie', narrower: 'asPie' };
  if (/^quadrantchart\b/.test(first)) return { family: 'quadrant', narrower: 'asQuadrant' };
  if (/^gantt\b/.test(first)) return { family: 'gantt', narrower: 'asGantt' };
  return { family: 'unknown', narrower: 'the matching as* helper' };
}

function buildAgentTaskPrompt() {
  var source = editor.value.trim();
  var detected = detectAgentFamily(source);
  return 'Use Agentic Mermaid locally.\n\n'
    + 'Task: Describe the diagram edit you want, then apply it to the Mermaid source below.\n\n'
    + 'Detected family: ' + detected.family + '\n'
    + 'Expected trace: parseMermaid → ' + detected.narrower + ' → mutate(...) → verifyMermaid → serializeMermaid\n\n'
    + 'Rules:\n'
    + '- Do not call the website as a render API.\n'
    + '- Parse with parseMermaid first.\n'
    + '- Use typed mutation ops when the family supports them; otherwise preserve source and ask before lossy edits.\n'
    + '- Run verifyMermaid before serialize, render, commit, or return.\n'
    + '- Return Mermaid source only after structural warnings are clear.\n\n'
    + 'Mermaid source:\n```mermaid\n'
    + (source || 'flowchart TD\n  A[Start] --> B[Edit me]')
    + '\n```';
}

function copyAgentTask() {
  writeClipboardText(buildAgentTaskPrompt(), 'Agent task prompt copied!', 'Copy agent task failed.', copyAgentTaskBtn);
}

function clearEditor() {
  editor.value = '';
  updateLineNumbers();
  updateCursorPos();
  previewInner.innerHTML = emptyPreviewHtml();
  if (typeof setTextOutputs === 'function') setTextOutputs('', '');
  statusText.textContent = 'Ready';
  statusText.className = '';
  renderTime.textContent = '';
  if (typeof resetVerifyPanel === 'function') resetVerifyPanel('Waiting for source');
  if (typeof updateExportAvailability === 'function') updateExportAvailability();
  if (typeof markActiveExample === 'function') markActiveExample('');
  window.history.replaceState(null, '', window.location.pathname);
  showToast('Started a blank diagram.');
}

var copySourceBtn = document.getElementById('copy-source-btn');
if (copySourceBtn) copySourceBtn.addEventListener('click', copySource);
var copyAgentTaskBtn = document.getElementById('copy-agent-task-btn');
if (copyAgentTaskBtn) copyAgentTaskBtn.addEventListener('click', copyAgentTask);

function selectTextOutput(kind) {
  var unicodeWrap = document.getElementById('unicode-output-wrap');
  var asciiWrap = document.getElementById('ascii-output-wrap');
  var unicodeTab = document.getElementById('unicode-output-tab');
  var asciiTab = document.getElementById('ascii-output-tab');
  var showAscii = kind === 'ascii';
  if (unicodeWrap) { unicodeWrap.hidden = showAscii; unicodeWrap.classList.toggle('active', !showAscii); }
  if (asciiWrap) { asciiWrap.hidden = !showAscii; asciiWrap.classList.toggle('active', showAscii); }
  if (unicodeTab) { unicodeTab.classList.toggle('active', !showAscii); unicodeTab.setAttribute('aria-selected', showAscii ? 'false' : 'true'); unicodeTab.tabIndex = showAscii ? -1 : 0; }
  if (asciiTab) { asciiTab.classList.toggle('active', showAscii); asciiTab.setAttribute('aria-selected', showAscii ? 'true' : 'false'); asciiTab.tabIndex = showAscii ? 0 : -1; }
  if (!showAscii && typeof fitUnicodeOutput === 'function') fitUnicodeOutput();
}

document.querySelectorAll('[data-output-tab]').forEach(function(btn) {
  btn.addEventListener('click', function() { selectTextOutput(btn.dataset.outputTab); });
  btn.addEventListener('keydown', function(e) {
    if (e.key !== 'ArrowLeft' && e.key !== 'ArrowRight') return;
    e.preventDefault();
    var next = btn.dataset.outputTab === 'ascii' ? 'unicode' : 'ascii';
    selectTextOutput(next);
    var nextBtn = document.querySelector('[data-output-tab="' + next + '"]');
    if (nextBtn) nextBtn.focus();
  });
});

if (copyTextOutputBtn) copyTextOutputBtn.addEventListener('click', function() {
  var active = document.querySelector('.text-output.active code');
  var value = active ? active.textContent : '';
  writeClipboardText(value || '', 'Text output copied!', 'Copy text output failed.', copyTextOutputBtn);
});

document.addEventListener('click', function(e) {
  var clearBtn = e.target.closest('[data-action="clear-editor"]');
  if (!clearBtn) return;
  clearEditor();
  if (typeof setExamplesSidebarOpen === 'function') setExamplesSidebarOpen(false);
});


var exportScale = 4;
var exportDropdown = document.getElementById('export-dropdown');
var exportMainBtn = document.getElementById('export-main-btn');
var exportChevronBtn = document.getElementById('export-chevron-btn');
var exportRequiresSvgButtons = [
  exportMainBtn,
  document.getElementById('export-png-btn'),
  document.getElementById('export-svg-btn'),
  document.getElementById('copy-svg-btn'),
  document.getElementById('copy-image-btn'),
].filter(Boolean);

function hasRenderedSvg() {
  return previewInner.querySelector('svg') !== null;
}

function updateExportAvailability() {
  var enabled = hasRenderedSvg();
  exportRequiresSvgButtons.forEach(function(btn) {
    btn.disabled = !enabled;
    btn.setAttribute('aria-disabled', enabled ? 'false' : 'true');
  });
}

var exportPopup = createPopupController({
  popup: exportDropdown,
  trigger: exportChevronBtn,
  visibility: { toggleTriggerClass: false },
  beforeOpen: updateExportAvailability,
  afterOpen: function(meta) {
    if (meta && meta.focusFirst) {
      var first = exportDropdown.querySelector('button:not(:disabled)');
      if (first) first.focus();
    }
  },
  contains: function(target) { return !!target.closest('#export-wrap'); },
});

function setExportDropdownOpen(open, focusFirst) {
  exportPopup.setOpen(open, { focusFirst: !!focusFirst });
}

exportDropdown.querySelectorAll('button').forEach(function(btn) { btn.setAttribute('role', 'menuitem'); });
exportMainBtn.addEventListener('click', function() {
  exportPNG();
});

document.getElementById('size-pills').addEventListener('click', function(e) {
  var pill = e.target.closest('.size-pill');
  if (!pill) return;
  exportScale = parseInt(pill.dataset.scale, 10);
  document.querySelectorAll('.size-pill').forEach(function(p) { p.classList.remove('active'); });
  pill.classList.add('active');
});

function getSvgEl() {
  var el = previewInner.querySelector('svg');
  if (!el) {
    showToast('Load or write a diagram before exporting.');
    updateExportAvailability();
    return null;
  }
  return el;
}

function serializeSvg(svgEl) {
  return new XMLSerializer().serializeToString(svgEl);
}

function svgToPngBlob(svgEl, scale, cb) {
  var serialized = serializeSvg(svgEl);
  var svgBlob = new Blob([serialized], { type: 'image/svg+xml;charset=utf-8' });
  var url = URL.createObjectURL(svgBlob);
  var img = new Image();
  img.onload = function() {
    var canvas = document.createElement('canvas');
    var w = img.naturalWidth  || svgEl.viewBox.baseVal.width  || 800;
    var h = img.naturalHeight || svgEl.viewBox.baseVal.height || 600;
    canvas.width  = w * scale;
    canvas.height = h * scale;
    var ctx = canvas.getContext('2d');
    ctx.scale(scale, scale);
    ctx.drawImage(img, 0, 0);
    URL.revokeObjectURL(url);
    canvas.toBlob(cb, 'image/png');
  };
  img.onerror = function() { URL.revokeObjectURL(url); showToast('PNG export failed.'); };
  img.src = url;
}

function exportPNG() {
  var svgEl = getSvgEl(); if (!svgEl) return;
  svgToPngBlob(svgEl, exportScale, function(blob) {
    var url = URL.createObjectURL(blob);
    var a = document.createElement('a');
    a.href = url; a.download = 'diagram.png'; a.click();
    URL.revokeObjectURL(url);
    showToast('PNG saved (' + exportScale + 'x)');
    setExportDropdownOpen(false, false);
  });
}

function exportSVG() {
  var svgEl = getSvgEl(); if (!svgEl) return;
  var data = serializeSvg(svgEl);
  var blob = new Blob([data], { type: 'image/svg+xml;charset=utf-8' });
  var url = URL.createObjectURL(blob);
  var a = document.createElement('a');
  a.href = url; a.download = 'diagram.svg'; a.click();
  URL.revokeObjectURL(url);
  showToast('SVG saved!');
  setExportDropdownOpen(false, false);
}

function copySVG() {
  var svgEl = getSvgEl(); if (!svgEl) return;
  writeClipboardText(serializeSvg(svgEl), 'SVG copied to clipboard!', 'Copy SVG failed.', document.getElementById('copy-svg-btn'));
}

function copyImage() {
  var svgEl = getSvgEl(); if (!svgEl) return;
  svgToPngBlob(svgEl, exportScale, function(blob) {
    try {
      navigator.clipboard.write([new ClipboardItem({ 'image/png': blob })]).then(function() {
        setCopyFeedback(document.getElementById('copy-image-btn'), 'ok');
        showToast('Image copied to clipboard!');
        setExportDropdownOpen(false, false);
      }).catch(function() {
        setCopyFeedback(document.getElementById('copy-image-btn'), 'err');
        showToast('Copy PNG failed.');
      });
    } catch(e) { setCopyFeedback(document.getElementById('copy-image-btn'), 'err'); showToast('Copy not supported in this browser.'); }
  });
}

function copyURL() {
  updateHash();
  writeClipboardText(window.location.href, 'URL copied to clipboard!', 'Copy link failed.', document.getElementById('copy-link-btn'));
}

document.getElementById('export-png-btn').addEventListener('click', exportPNG);
document.getElementById('export-svg-btn').addEventListener('click', exportSVG);
document.getElementById('copy-svg-btn').addEventListener('click', copySVG);
document.getElementById('copy-image-btn').addEventListener('click', copyImage);
document.getElementById('copy-link-btn').addEventListener('click', copyURL);
updateExportAvailability();

document.addEventListener('keydown', function(e) {
  if (e.target === editor) return;
  if ((e.metaKey || e.ctrlKey) && !e.shiftKey && e.key.toLowerCase() === 's') { e.preventDefault(); exportPNG(); }
  if ((e.metaKey || e.ctrlKey) &&  e.shiftKey && e.key.toLowerCase() === 's') { e.preventDefault(); exportSVG(); }
});


var isResizing = false;
var resizeStartX = 0;
var resizeStartW = 0;

function isNarrowViewport() {
  return window.matchMedia && window.matchMedia('(max-width: 760px)').matches;
}

function resizeBounds() {
  return {
    min: 280,
    max: Math.max(280, window.innerWidth * 0.75),
  };
}

function setPanelWidth(px) {
  if (isNarrowViewport()) {
    panelLeft.style.width = '';
    if (resizeHandle) resizeHandle.setAttribute('aria-disabled', 'true');
    return;
  }
  var bounds = resizeBounds();
  var newW = Math.max(bounds.min, Math.min(bounds.max, px));
  panelLeft.style.width = newW + 'px';
  if (resizeHandle) {
    resizeHandle.setAttribute('aria-disabled', 'false');
    resizeHandle.setAttribute('aria-valuemin', String(Math.round(bounds.min)));
    resizeHandle.setAttribute('aria-valuemax', String(Math.round(bounds.max)));
    resizeHandle.setAttribute('aria-valuenow', String(Math.round(newW)));
    resizeHandle.setAttribute('aria-valuetext', 'Source panel width ' + Math.round(newW) + ' pixels');
  }
}

function startResize(e) {
  isResizing = true;
  resizeStartX = e.clientX;
  resizeStartW = panelLeft.getBoundingClientRect().width;
  resizeHandle.classList.add('dragging');
  document.body.style.cursor = 'col-resize';
  document.body.style.userSelect = 'none';
  if (resizeHandle.setPointerCapture && e.pointerId != null) resizeHandle.setPointerCapture(e.pointerId);
}

function moveResize(e) {
  if (!isResizing) return;
  var dx = e.clientX - resizeStartX;
  setPanelWidth(resizeStartW + dx);
}

function endResize(e) {
  if (!isResizing) return;
  isResizing = false;
  resizeHandle.classList.remove('dragging');
  document.body.style.cursor = '';
  document.body.style.userSelect = '';
  if (resizeHandle.releasePointerCapture && e && e.pointerId != null) resizeHandle.releasePointerCapture(e.pointerId);
}

resizeHandle.addEventListener('pointerdown', function(e) {
  if (isNarrowViewport()) return;
  e.preventDefault();
  startResize(e);
});

document.addEventListener('pointermove', moveResize);
document.addEventListener('pointerup', endResize);
document.addEventListener('pointercancel', endResize);

resizeHandle.addEventListener('keydown', function(e) {
  if (isNarrowViewport()) return;
  var current = panelLeft.getBoundingClientRect().width;
  var bounds = resizeBounds();
  var next = current;
  if (e.key === 'ArrowLeft') next = current - (e.shiftKey ? 48 : 16);
  else if (e.key === 'ArrowRight') next = current + (e.shiftKey ? 48 : 16);
  else if (e.key === 'Home') next = bounds.min;
  else if (e.key === 'End') next = bounds.max;
  else return;
  e.preventDefault();
  setPanelWidth(next);
});

function syncResponsivePanelWidth() {
  if (isNarrowViewport()) {
    panelLeft.style.width = '';
    if (resizeHandle) resizeHandle.setAttribute('aria-disabled', 'true');
  } else {
    setPanelWidth(panelLeft.getBoundingClientRect().width || 420);
  }
}

if (typeof window !== 'undefined') window.addEventListener('resize', syncResponsivePanelWidth);
syncResponsivePanelWidth();


var toastTimer;
function showToast(msg) {
  toast.textContent = msg;
  toast.classList.add('show');
  clearTimeout(toastTimer);
  toastTimer = setTimeout(function() { toast.classList.remove('show'); }, 2500);
}


var isDark = localStorage.getItem("bm-editor-dark") === "true";

var diagramThemeIsAuto = true;

function applyColorMode(dark, force) {
  isDark = dark;
  var darkLightBtn = document.getElementById("dark-light-btn");
  if (darkLightBtn) {
    darkLightBtn.classList.toggle("is-dark", dark);
    darkLightBtn.setAttribute("aria-label", dark ? "Switch to light mode" : "Switch to dark mode");
  }
  localStorage.setItem("bm-editor-dark", dark ? "true" : "false");

  // Page chrome follows the site Paper/Dusk palette. The diagram theme is controlled
  // separately by the dropdown so color mode does not silently rewrite diagrams.
  applyThemeToPage(state.theme);
  // These may not exist yet during initial load – guarded calls
  if (typeof updateThemeButton === "function") updateThemeButton();
  if (typeof refreshAllColorUIs === "function") refreshAllColorUIs();
  if (typeof scheduleRender === "function") scheduleRender(0);
}

document
  .getElementById("dark-light-btn")
  .addEventListener("click", function () {
    applyColorMode(!isDark, true);
  });


// Theme dropdown logic
var themeBtnLabel = document.getElementById("theme-btn-label");
var themeBtnSwatch = document.getElementById("theme-btn-swatch");
var themeDropdownBtn = document.getElementById("theme-dropdown-btn");

function updateThemeButton() {
  var key = state.theme;
  if (key && THEMES[key]) {
    themeBtnLabel.textContent =
      themeDropdownBtn.getAttribute("data-label-" + key) || key;
    themeBtnSwatch.style.background = THEMES[key].bg;
    themeBtnSwatch.style.display = "";
  } else {
    themeBtnLabel.textContent = "Default";
    themeBtnSwatch.style.background = "";
    themeBtnSwatch.style.display = "none";
  }
  // Update active state in dropdown
  themeMenu.querySelectorAll(".theme-dropdown-item").forEach(function (item) {
    var active = item.dataset.theme === key;
    item.classList.toggle("active", active);
    item.setAttribute("aria-selected", active ? "true" : "false");
    item.tabIndex = themeMenu.classList.contains("open") && active ? 0 : -1;
  });
}

function setTheme(key) {
  state.theme = key;
  diagramThemeIsAuto = false;
  if (key) {
    localStorage.setItem("bm-editor-theme", key);
  } else {
    localStorage.removeItem("bm-editor-theme");
  }
  applyThemeToPage(key);
  updateThemeButton();
  refreshAllColorUIs();
  scheduleRender(0);
}

var themeMenuPopup = createPopupController({
  popup: themeMenu,
  trigger: themeDropdownBtn,
  visibility: { manageTabStops: false },
  afterOpen: function(meta) {
    syncThemeMenuTabStops(true);
    if (meta && meta.focusFirst) {
      var active = themeMenu.querySelector(".theme-dropdown-item.active") || themeMenu.querySelector(".theme-dropdown-item");
      if (active) active.focus();
    }
  },
  afterClose: function() { syncThemeMenuTabStops(false); },
  contains: function(target) { return !!target.closest("#theme-dropdown-wrap"); },
});

function syncThemeMenuTabStops(open) {
  themeMenu.querySelectorAll(".theme-dropdown-item").forEach(function(item) {
    var active = item.classList.contains("active");
    item.tabIndex = open && active ? 0 : -1;
  });
}

function setThemeMenuOpen(open, focusActive) {
  themeMenuPopup.setOpen(open, { focusFirst: !!focusActive });
}

// Click item
themeMenu.addEventListener("click", function (e) {
  var item = e.target.closest(".theme-dropdown-item");
  if (!item) return;
  setTheme(item.dataset.theme || "");
  setThemeMenuOpen(false, false);
  themeDropdownBtn.focus();
});

themeMenu.addEventListener("keydown", function(e) {
  var items = Array.prototype.slice.call(themeMenu.querySelectorAll(".theme-dropdown-item"));
  var current = document.activeElement && document.activeElement.classList.contains("theme-dropdown-item") ? document.activeElement : null;
  var index = Math.max(0, items.indexOf(current));
  if (["ArrowDown", "ArrowUp", "Home", "End"].includes(e.key)) {
    e.preventDefault();
    var next = index;
    if (e.key === "Home") next = 0;
    else if (e.key === "End") next = items.length - 1;
    else next = (index + (e.key === "ArrowDown" ? 1 : -1) + items.length) % items.length;
    items[next].tabIndex = 0;
    items[next].focus();
  }
  if (e.key === "Enter" || e.key === " ") {
    e.preventDefault();
    if (current) current.click();
  }
});

// Store label data for lookup
themeMenu.querySelectorAll(".theme-dropdown-item").forEach(function (item) {
  var key = item.dataset.theme || "";
  themeDropdownBtn.setAttribute("data-label-" + key, item.textContent.trim());
});

// Apply initial dark/light mode (must happen after all DOM refs + functions are ready)
applyColorMode(isDark);

// Restore saved theme, otherwise start on the fork's default salmon theme.
var savedTheme = localStorage.getItem("bm-editor-theme") || "";
if (savedTheme && THEMES[savedTheme]) {
  state.theme = savedTheme;
  diagramThemeIsAuto = false;
} else if (!state.theme || !THEMES[state.theme]) {
  state.theme = DEFAULT_EDITOR_THEME;
  diagramThemeIsAuto = true;
}
applyThemeToPage(state.theme);
updateThemeButton();
setThemeMenuOpen(false, false);

// Load from URL hash or start blank.
var DEFAULT_SOURCE = "";

var hashSource = getHashSource();
var queryExampleId = getQueryExampleId();
var loadedInitialExample = false;
if (hashSource) {
  editor.value = hashSource;
  applyThemeToPage(state.theme);
  updateThemeButton();
  refreshAllColorUIs();
} else if (queryExampleId && typeof loadEditorExample === 'function' && findEditorExample(queryExampleId)) {
  loadEditorExample(queryExampleId);
  loadedInitialExample = true;
} else {
  editor.value = DEFAULT_SOURCE;
}

if (!loadedInitialExample) {
  updateLineNumbers();
  scheduleRender(0);
}
